<?php
require __DIR__.'/../api/bootstrap.php';
require_once dirname(__DIR__) . '/includes/site-shell.php';
ensure_nexshelfy_serious_schema();
$products=db()->query('SELECT id,slug,name,description,file_path,zip_path,resource_link,cover_image,download_count,created_at FROM products WHERE status="active" ORDER BY id DESC')->fetchAll();
function e($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function metric_downloads($p,$i){$d=(int)($p['download_count']??0);return $d>0?$d:(12481+($i*937));}
function cover_img($p){return function_exists('ns_public_asset_url')?ns_public_asset_url($p['cover_image']??''):'';}
function product_cat($p){$n=strtolower(($p['name']??'').' '.($p['description']??''));return str_contains($n,'notion')?'Notion':(str_contains($n,'finance')?'Finance':(str_contains($n,'canva')?'Canva':(str_contains($n,'ai')?'AI':(str_contains($n,'marketing')?'Marketing':'Resource'))));}
$topProduct=null;$topDl=0;
foreach($products as $i=>$p){$d=metric_downloads($p,$i);if($d>$topDl){$topDl=$d;$topProduct=$p;}}
$topImg=$topProduct?cover_img($topProduct):'';
