<section class="ns-blog-section"><div class="ns-section-title"><span>Featured Free Products</span><h2>Most downloaded free products</h2><a href="#productGrid">Browse all ↓</a></div><div class="cp-grid ns-premium-product-grid" id="productGrid"><?php foreach($products as $i=>$p):$type=(!empty($p['resource_link'])?'link':'download');$dl=metric_downloads($p,$i);$needle=strtolower($p['name'].' '.$p['description'].' '.product_cat($p));$img=cover_img($p);?><article class="cp-card ns-premium-resource-card ns-clean-shop-card" data-title="<?=e($needle)?>" data-type="<?=e($type)?>"><a class="cp-cover ns-resource-cover <?= $img?'has-image':'no-image' ?>" href="/shop/<?=e($p['slug'])?>/"><?php if($img): ?><img class="ns-cover-photo" src="<?=e($img)?>" alt="<?=e($p['name'])?>"><?php endif; ?><span><?=e(product_cat($p))?></span></a><button class="ns-card-heart" data-ns-product-save data-slug="<?=e($p['slug'])?>" aria-label="Save product">♡</button><div class="cp-card-body"><div class="ns-card-pills"><span>FREE · <?= $type==='link'?'LINK':'PDF/ZIP'?></span></div><h2><a href="/shop/<?=e($p['slug'])?>/"><?=e($p['name'])?></a></h2><p><?=e($p['description'] ?: 'A curated NexShelfy digital product.')?></p><div class="ns-card-footer-row"><small><b><?=number_format($dl)?></b> downloads</small><div class="ns-card-footer-actions"><button class="ns-mini-action primary ns-icon-only" type="button" data-ns-free-download data-href="/api/free-download.php?type=product&amp;slug=<?=rawurlencode($p['slug'])?>" title="Download" aria-label="Download">⬇</button><a class="ns-mini-action ns-icon-only" href="/shop/<?=e($p['slug'])?>/" title="Preview" aria-label="Preview">👁</a></div></div></div></article><?php endforeach;?><?php if(!$products):?><div class="cp-empty">No active free products yet. Add products from admin → Free Products.</div><?php endif;?></div></section>
<section class="ns-blog-lanes ns-blog-section"><div><span>Most Downloaded</span><h3>Proven templates</h3><p>Resources people save and use repeatedly.</p></div><div><span>Recently Added</span><h3>Fresh this month</h3><p>New systems, assets and practical downloads.</p></div><div><span>Editor Picks</span><h3>Curated quality</h3><p>The best resources for creators and freelancers.</p></div><div><span>Popular Categories</span><h3>Notion, Canva, AI</h3><p>Browse resources by the tools you already use.</p></div></section></main><?php ns_site_footer(); ?><script src="/assets/nexshelfy-app.js?v=20260717-final-ui-2"></script></body></html>
